ControlflowRule.Definition:
state start START;
state VAR;
state CHK;
state CALL;
state error NCHK;

var x;

pattern fns{$acos(x)|$asin(x)|$atan2(x,...)|$atan2(...,x)|$log(x)|$log10(x)|$pow(x,...)|$pow(...,x)|$sqrt(x)}

START -> VAR{ #any_declaration(x) | #param(x, ?) | x = ?}
VAR -> CHK{ #compare(x, ?) |isless(x,?) |isgreater(x,?) }
CHK -> CALL{pattern fns | $sqrt(x)}
VAR -> NCHK{ pattern fns | $sqrt(x) }

state start START;
			state ALLOC;
			state TEST;
			state RETURN;
			state error NOTEST;

			var foo;

			pattern allocate{ foo = $malloc(...)|foo = $new(...) }
			pattern test{ #ifblock(foo, ?, true) | #ifblock(foo, ?, false) }

			START -> ALLOC{ pattern allocate }
			ALLOC -> TEST{ pattern test }
			ALLOC -> RETURN{ #return(foo) }
			ALLOC -> NOTEST{ foo }

state start START;
			state GET;
			state END;
			state error BAD;

			var str;

			pattern alter{ $cat(str, ...) | $cpy(str, ...) | str = ? }

			START -> GET{ str = $c_str(...) }
			GET -> END{ #end_scope(str) }
			GET -> BAD{ pattern alter }

state start START;
			state ASSIGN;
			state error ARG;
			state END;
			state error CALL;

			var foo;
			var str;

			pattern equal{ foo= $begin(...) | $data(...) | $end(...) | $at(...)  }

			START -> ASSIGN{ foo = str.$begin(...) }
			ASSIGN -> ARG{ str.$insert(foo, ...) }
			ASSIGN -> END{ #end_scope(foo) }

state start START;
			state error CSTR;
			state END;
			state error BAD;

			var str;
			var ps;
			pattern alter{ ps.$append(...) }

			START -> CSTR{ str = ps.$c_str(...) }
			CSTR -> END{ #end_scope(str) }
			CSTR -> BAD{ pattern alter }
